var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"이, 이것 봐. 우리한테는 말 한마디 없이 이렇게 많은 엘릭서를 만들어 뒀잖아.","JPN":"こ、これを見ろ。俺たちには内緒でこんなにたくさんのエリクサーを作っていたじゃないか。","ENG":"L-look! He's already made all this Elixir, without so much as a word to us.","TWN":"喂，你看！竟然瞞著我們做了這麼多聖水。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"주교님은 자경단 놈들을 잡으러 가셨지. 지금이 기회야.","JPN":"司教様は自警団のやつらを捕まえに行った。今がチャンスだ。","ENG":"The Bishop went after the vigilantes. Now's our chance.","TWN":"趁主教去追那些自衛隊的傢伙，就是現在！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"흐흐, 그렇게 충성했는데 고물 로켓탄 좀 불발났다고 등신 취급했겠다?","JPN":"ふん、あんなに忠誠を尽くしたのに、ポンコツのロケット弾が不発したからってクズ扱いしやがって！","ENG":"Ha! We've been nothing but loyal but he treats us like crap just because of some faulty rocket? This'll teach him!","TWN":"呵呵，原本很忠誠的，結果不說話還真當我們是笨蛋嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"젠장, 돌아와서 보관실이 텅 빈 걸 발견하고 무슨 표정을 지을지 봐야 하는데!","JPN":"ちっ、帰ってきた後に保管室ががらんとしているのを見てどんな表情をするか、見てやりたいけどな！","ENG":"Too bad we won't get to see the look on his stupid face when he finds this place empty!","TWN":"該死！真想看看他回來後，發現保管室空蕩蕩會是什麼表情。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"자자, 어서 챙겨서 여길 뜨자고! 이제 우린 떼부자야!","JPN":"さあさあ、これをまとめてさっさとここを出よう！　もう俺らは大金持ちさ！","ENG":"Come on, now. Let's grab the goods and bail! We're rich now!","TWN":"快點！東西趕快拿一拿離開吧！我們要發大財囉～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"이런, 우리 회사 재산을 마음대로 훔쳐가면 안 되지.","JPN":"おや、会社の財産を勝手に盗むのはダメだぜ。","ENG":"Tut, tut. You can't just steal company property like that.","TWN":"搞什麼，怎麼可以順手牽羊公司的財產呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"컥……! 크륵……!","JPN":"ぐっ……！　がはっ……！","ENG":"Ack...! Hngh...!","TWN":"唔……！咳咳……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"뭐, 뭐냐! 너희들은! 여기는 마젤란 예언회의 신성한……!","JPN":"な、何だ！　お前たちは！　ここはマジェラン預言会の聖なる……！","ENG":"W-what the… Who are you?! You're trespassing on the Society's sacred-","TWN":"你…你們是誰？這裡可是麥哲倫預言會神聖的…！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"커, 커흑……. 사, 살려 줘……. 병원에…….","JPN":"が、がはっ……た、助けて……病院に……","ENG":"Ack… P-please… Take me to the hospital…","TWN":"呃嗚……救我……醫院……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"컥……. 커억……. 그만, 제발…….","JPN":"ぐあっ……ぐほっ……もう、やめてくれ……","ENG":"Ack... Hngh… Please stop…","TWN":"咳咳……嗚…住手……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L32_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"이런, 믿음으로 얼마나 버티나 보려고 했는데 금방 죽어 버리잖아.","JPN":"やれやれ、信仰心でどれだけ持ちこたえるか見てやろうとしたのに、すぐ死んじまったじゃないか。","ENG":"Oh dear. I wanted to see how long your faith would keep you alive. That was too quick.","TWN":"什麼嘛～本來想看看靠著信仰能撐多久的，結果一下就死掉啦！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"하하. 급소 맞추는 게 버릇 되셔서 그렇죠, 대장님.","JPN":"ハハ、急所を当てるのが癖になっているからですよ、隊長。","ENG":"Haha. It's because you've made a habit of shooting them in the vitals, sir.","TWN":"哈哈。那是因為隊長你都命中要害的嘛～"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"시설에 남아 있던 자들은 모두 제압했습니다, 경호실장님.","JPN":"施設に残っていた者たちは全員制圧しました、室長。","ENG":"We've taken care of everyone in the building, ma'am.","TWN":"護衛室長，留在設施的人已經全部控制住了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 잘했어. 저런 주인도 몰라보는 못생긴 벌레들 때문에 연주하기도 피곤하거든.","JPN":"フフッ、よくやったわ。雇い主すら忘れる醜い虫けらどもは演奏の邪魔になるもの。","ENG":"Hehe, well done. It was a hassle trying to keep the music going when those ugly worms won't even recognize their master.","TWN":"唷呵～幹得好！那些連主人都不認得的走狗，搞得我連要演奏都覺得累。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래서 이게 얘들이 만들었다던 엘릭서인가?","JPN":"それで、あいつらが作ったエリクサーはこれかしら？","ENG":"So is this the Elixir these guys concocted?","TWN":"這就是他們製作的聖水嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 주교란 남자, 자기가 복제할 수 있다고 허풍을 떨던데 어디 맛 좀 볼까?","JPN":"あの司教様とかいう男、自分で複製できると偉そうにしてたけど、味見してみようかしら。","ENG":"That Bishop guy's been claiming he could replicate it. Let's see if he was bluffing or not.","TWN":"那個叫主教的男人，一直吹牛自己可以複製得出來，我就來嚐嚐看吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"……어떠십니까?","JPN":"……いかがですか？","ENG":"…How's the taste?","TWN":"……怎麼樣呢？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"퉷. 엘릭서는 무슨. 그냥 평범한 싸구려 마약이야.","JPN":"ぺっ。エリクサーどころか、ありふれた安物の薬物だわ。","ENG":"Ptooey. This is no Elixir. It's just an average street drug only junkies would take.","TWN":"嗟！什麼鬼聖水，不過就是普通的廉價毒品！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하긴 처음부터 가망이 없긴 했지. 원액은 리플레이서 신디케이트가 조달해 줬을 테니까.","JPN":"まあ、最初から見込みはなかったけどね。原液はリプレイサー・シンジケートから調達していたから。","ENG":"I suppose it was a long shot after all. Now that they don't have the Replacer Syndicate to supply them with the real juice.","TWN":"反正我從一開始就不抱希望，畢竟原液是由克隆集團調配的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리 대표님, 또 실적 못 낸다고 실망하겠네. 이를 어쩌나.","JPN":"うちの代表、また実績をあげられないとがっかりしちゃうわね、どうしよう。","ENG":"So we've got nothing again. The boss isn't going to like this. Oh dear.","TWN":"我們代表又會該該叫，說我們辦事不力囉～這可怎麼辦呢？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"그럴 줄 알고 보초들을 생포했습니다. 실험 재료로 선물해 주시죠.","JPN":"そうだと思って見張りたちは生かしておきました。実験材料としてお渡ししましょう。","ENG":"That's why I took the liberty of capturing the guards. You could give them to him as a present.","TWN":"所以以防萬一，我有留哨兵活命，把他們送給代表當作實驗材料吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어머, 우리 조장님은 유달리 똑똑하네. 인간 주제에.","JPN":"あら、やっぱりうちの隊長は気が利くわね。人間のくせに。","ENG":"Aww, you're a clever little cookie, aren't you? For a human, anyway.","TWN":"哇喔，明明都是人類，但隊長特別聰明呢！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"하하, 감사합니다. 실장님.","JPN":"ハハハ、ありがとうございます、室長。","ENG":"Haha, thank you, ma'am.","TWN":"哈哈，謝謝室長。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그러면 나는 하청 행세 하면서 우릴 속인 벌레 놈을 추궁하러 다녀올게.","JPN":"それじゃあ私は下請けのふりをして私たちを騙した虫けらを追及しに行ってくるわ。","ENG":"Well, I'm off to kill that swindling worm of a subcontractor.","TWN":"那我去找那些騙人的承包商嚴刑拷問一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌이란 여자는 어떻게 하면 되겠습니까?","JPN":"ホライズンという女はどうしましょうか？","ENG":"What should we do with the Horizon girl?","TWN":"還有那個叫地平線女生該怎麼辦呢？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"대표님이 말했잖아. 죽이지 말고 자기 앞에 데려오라고.","JPN":"代表が言ったじゃない。殺さずに連れて来てって。","ENG":"The boss was clear about what he wanted. Bring her to him alive.","TWN":"代表不是有說要活捉她。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"나머지는 너희들 마~음대로 해.","JPN":"残りは好きにしていいわ。","ENG":"As for the rest, do whatever you want.","TWN":"其他的你們就自己看～著辦吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};